let state=load();let current='dashboard';let editContext=null;let calendarDate=new Date();let activityTypeFilter='All';
function load(){try{let data={...structuredClone(seed),...JSON.parse(localStorage.getItem(STORAGE_KEY)||'{}')};data.members=data.members.map((m,i)=>({...m,subunit:['Finance','Admin','Technical','Member','Welfare'].includes(m.subunit)?m.subunit:'Member',skill:m.skill||['General schedule','Scripture Projection','using VMIX'][i%3],skillLevel:m.skillLevel||['Advanced','Intermediate','Beginner'][i%3]}));return data}catch{return structuredClone(seed)}}
function save(message='Changes saved'){localStorage.setItem(STORAGE_KEY,JSON.stringify(state));document.getElementById('lastSaved').textContent=cloudSession?'Syncing…':'Saved offline';toast(message);render();queueCloudSync()}
function id(prefix){return prefix+Date.now().toString(36)+Math.random().toString(36).slice(2,5)}
function esc(v=''){return String(v).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]))}
function money(v){return new Intl.NumberFormat('en-NG',{style:'currency',currency:'NGN',maximumFractionDigits:0}).format(Number(v)||0)}
function dateFmt(v,opts={day:'numeric',month:'short',year:'numeric'}){if(!v)return '—';return new Date(v+'T00:00:00').toLocaleDateString('en-NG',opts)}
function initials(n=''){return n.split(' ').map(x=>x[0]).slice(0,2).join('').toUpperCase()}
function toast(msg){let t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');clearTimeout(window.toastTimer);window.toastTimer=setTimeout(()=>t.classList.remove('show'),2300)}
document.getElementById('nav').innerHTML=pages.map(([k,i,l])=>`<button class="nav-button" data-page="${k}"><span class="nav-icon">${i}</span>${l}</button>`).join('');
document.getElementById('nav').onclick=e=>{let b=e.target.closest('[data-page]');if(b){current=b.dataset.page;closeMenu();render()}};
document.getElementById('menuButton').onclick=()=>{document.getElementById('sidebar').classList.add('open');document.getElementById('scrim').classList.add('show')};
document.getElementById('scrim').onclick=closeMenu;function closeMenu(){document.getElementById('sidebar').classList.remove('open');document.getElementById('scrim').classList.remove('show')}
document.getElementById('backupButton').onclick=backup;document.getElementById('restoreInput').onchange=restore;
function render(){document.querySelectorAll('.nav-button').forEach(b=>b.classList.toggle('active',b.dataset.page===current));document.getElementById('pageTitle').textContent=current==='notifications'?'Notifications':pages.find(p=>p[0]===current)[2];document.getElementById('view').innerHTML=views[current]();bindView();updateNotificationBadge();postRenderEnhancements()}
const metrics=()=>{let active=state.members.filter(m=>m.status==='Active').length,inactive=state.members.length-active,pending=state.designs.filter(d=>designStatus(d)!=='Past').length,training=state.activities.filter(a=>a.type==='Training'&&a.status!=='Completed').length;return {active,inactive,pending,training}};
const views={
dashboard(){let m=metrics(),upcoming=[...state.members].map(x=>({...x,next:nextBirthday(x.birthday)})).sort((a,b)=>a.next-b.next).slice(0,4);return `<section class="hero"><div><p class="eyebrow">WELCOME BACK</p><h2>Serving with clarity and excellence.</h2><p>Your department at a glance — everything updates as your records change.</p></div><div class="hero-date"><strong>${new Date().toLocaleDateString('en-NG',{weekday:'long'})}</strong><span>${new Date().toLocaleDateString('en-NG',{day:'numeric',month:'long',year:'numeric'})}</span></div></section><section class="metrics">${metric('Total members',state.members.length,'Department directory')}${metric('Active members',m.active,'Currently serving')}${metric('Inactive',m.inactive,'Away or unavailable')}${metric('Contributions',state.contributionTypes.filter(x=>x.status==='Active').length,'Active collections')}${metric('Pending designs',m.pending,'Needs attention')}${metric('Trainings',m.training,'Upcoming sessions')}</section><section class="grid-2"><div class="card"><div class="card-head"><div><h3>Upcoming celebrations</h3><p>Birthdays coming up next</p></div><button class="button small ghost right" data-page-jump="members">View members</button></div><div class="card-body list">${upcoming.map(x=>`<div class="list-item"><div class="date-tile"><b>${x.next.toLocaleDateString('en-NG',{month:'short'}).toUpperCase()}</b><strong>${x.next.getDate()}</strong></div><div class="grow"><strong>${esc(x.name)}</strong><small>${esc(x.subunit)} · Birthday</small></div><span class="pill active">${daysUntil(x.next)} days</span></div>`).join('')||empty('No birthdays recorded')}</div></div><div class="card"><div class="card-head"><div><h3>Quick actions</h3><p>Keep your records moving</p></div></div><div class="card-body quick-actions"><button class="quick-action" data-add="member"><span>＋ Add member</span><small>Grow the directory</small></button><button class="quick-action" data-add="activity"><span>＋ Plan activity</span><small>Meeting or training</small></button><button class="quick-action" data-add="design"><span>＋ Add design</span><small>Track creative work</small></button></div></div></section><section class="grid-2 grid-even" style="margin-top:18px"><div class="card"><div class="card-head"><div><h3>Next activities</h3><p>Department calendar</p></div></div><div class="card-body list">${state.activities.slice().sort((a,b)=>a.date.localeCompare(b.date)).slice(0,4).map(a=>`<div class="list-item"><div class="date-tile"><b>${dateFmt(a.date,{month:'short'}).toUpperCase()}</b><strong>${new Date(a.date+'T00:00:00').getDate()}</strong></div><div class="grow"><strong>${esc(a.title)}</strong><small>${esc(a.venue)} · ${esc(a.time)}</small></div><span class="pill ${a.status.toLowerCase().replace(' ','-')}">${esc(a.status)}</span></div>`).join('')||empty('No activities yet')}</div></div>${skillsCard()}</section>`},
members(){return `${tools('Search members…','member',['All status','Active','Inactive'])}<div class="card"><div class="card-head"><div><h3>Member directory</h3><p>${state.members.length} people recorded</p></div><button class="button small ghost right" id="csvMembers">↓ CSV export</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Member</th><th>Contact</th><th>Role / Sub-unit</th><th>Birthday</th><th>Skills</th><th>Status</th><th></th></tr></thead><tbody>${state.members.map(x=>`<tr data-search="${esc(Object.values(x).join(' ').toLowerCase())}" data-status="${x.status}"><td><div class="person"><span class="person-badge">${initials(x.name)}</span><div><strong>${esc(x.name)}</strong><small>${esc(x.functions||'No functions')}</small></div></div></td><td>${esc(x.phone)}<br><small>${esc(x.email)}</small></td><td><strong>${esc(x.role)}</strong><br><small>${esc(x.subunit)}</small></td><td>${dateFmt(x.birthday,{day:'numeric',month:'short'})}</td><td>${esc(x.skills||'—')}</td><td><span class="pill ${x.status.toLowerCase()}">${x.status}</span></td>${rowActions('member',x.id)}</tr>`).join('')}</tbody></table></div></div><div style="margin-top:18px">${skillsCard()}</div>`},
contributions(){let expected=state.contributionTypes.reduce((s,c)=>s+Number(c.amount)*state.members.length,0),received=state.payments.reduce((s,p)=>s+Number(p.amount),0),pct=expected?Math.round(received/expected*100):0;return `<div class="summary-strip">${summary('Expected',money(expected))}${summary('Received',money(received))}${summary('Outstanding',money(expected-received))}${summary('Collected',pct+'%')}</div><div class="page-tools"><button class="button primary" data-add="contribution">＋ Contribution type</button><button class="button gold" data-add="payment">＋ Record payment</button><span class="spacer"></span></div><div class="grid-2 grid-even"><div class="card"><div class="card-head"><div><h3>Contribution types</h3><p>Expected amount is per active member</p></div></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Contribution</th><th>Expected</th><th>Received</th><th>Progress</th><th></th></tr></thead><tbody>${state.contributionTypes.map(c=>{let got=state.payments.filter(p=>p.typeId===c.id).reduce((s,p)=>s+Number(p.amount),0),exp=Number(c.amount)*state.members.length,pc=exp?Math.round(got/exp*100):0;return `<tr><td><strong>${esc(c.name)}</strong><br><small>Due ${dateFmt(c.due)}</small></td><td>${money(exp)}</td><td>${money(got)}</td><td>${pc}%<div class="progress"><i style="width:${Math.min(pc,100)}%"></i></div></td>${rowActions('contribution',c.id)}</tr>`}).join('')||`<tr><td colspan="5">${empty('No contribution types')}</td></tr>`}</tbody></table></div></div><div class="card"><div class="card-head"><div><h3>Recent payments</h3><p>Individual member payments</p></div></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Member</th><th>Contribution</th><th>Amount</th><th>Date</th><th></th></tr></thead><tbody>${state.payments.slice().reverse().map(p=>`<tr><td>${esc(memberName(p.memberId))}</td><td>${esc(typeName(p.typeId))}</td><td><strong>${money(p.amount)}</strong></td><td>${dateFmt(p.date)}</td>${rowActions('payment',p.id)}</tr>`).join('')||`<tr><td colspan="5">${empty('No payments yet')}</td></tr>`}</tbody></table></div></div></div>`},
activities(){return `${tools('Search activities…','activity',['All status','Planned','In Progress','Completed'])}<div class="card"><div class="card-head"><div><h3>Department activities</h3><p>Meetings, trainings, outreaches and events</p></div></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Activity</th><th>Type</th><th>Date & time</th><th>Venue</th><th>Coordinator</th><th>Status</th><th></th></tr></thead><tbody>${state.activities.map(x=>`<tr data-search="${esc(Object.values(x).join(' ').toLowerCase())}" data-status="${x.status}"><td><strong>${esc(x.title)}</strong><br><small>${esc(x.notes)}</small></td><td>${esc(x.type)}</td><td>${dateFmt(x.date)} · ${esc(x.time)}</td><td>${esc(x.venue)}</td><td>${esc(x.coordinator)}</td><td><span class="pill ${x.status.toLowerCase().replace(' ','-')}">${x.status}</span></td>${rowActions('activity',x.id)}</tr>`).join('')}</tbody></table></div></div>`},
schedule(){return `<div class="page-tools"><button class="button primary" data-add="schedule">＋ Meeting schedule</button><button class="button gold" data-add="roster">＋ Work roster</button></div><div class="grid-2 grid-even"><div class="card"><div class="card-head"><div><h3>Meeting schedules</h3><p>Agendas ready to share and print</p></div></div><div class="card-body list">${state.schedules.map(x=>recordItem(x,'schedule','Meeting agenda',x.date,x.venue)).join('')||empty('No schedules yet')}</div></div><div class="card"><div class="card-head"><div><h3>Work rosters</h3><p>Team assignments for events</p></div></div><div class="card-body list">${state.rosters.map(x=>recordItem(x,'roster','Duty roster',x.date,x.venue,x.event)).join('')||empty('No rosters yet')}</div></div></div>`},
designs(){return `${tools('Search designs…','design',['All status','Pending','In Progress','Approved'])}<div class="design-grid">${state.designs.map(x=>`<article class="design-card" data-search="${esc(Object.values(x).join(' ').toLowerCase())}" data-status="${x.status}"><div class="design-thumb" ${x.thumbnail?`style="background-image:url('${esc(x.thumbnail)}');background-size:cover;background-position:center"`:''}><span>${x.thumbnail?'':esc(x.category)}</span></div><div class="design-info"><span class="pill ${x.status.toLowerCase().replace(' ','-')}">${esc(x.status)}</span><h4>${esc(x.title)}</h4><p>${dateFmt(x.date)} · ${esc(x.person)}</p><div class="actions"><a class="button small ghost" href="${esc(x.canva||'#')}" target="_blank" rel="noopener">Open Canva</a><button class="button small" data-edit="design" data-id="${x.id}">Edit</button><button class="button small danger" data-delete="design" data-id="${x.id}">Delete</button></div></div></article>`).join('')||empty('No designs yet')}</div>`},
reports(){return `<div class="notice">Reports reflect the information currently saved in this browser. Create a JSON backup regularly if you use more than one device.</div><div class="report-options"><div class="report-option"><div class="report-icon">▥</div><div><h4>Dashboard report</h4><p>Summary metrics, activities and celebrations</p></div><button class="button small primary" data-report="dashboard">Print / PDF</button></div><div class="report-option"><div class="report-icon">CSV</div><div><h4>Members table</h4><p>All member fields in spreadsheet format</p></div><button class="button small primary" id="csvMembers">Download</button></div><div class="report-option"><div class="report-icon">JSON</div><div><h4>Complete data backup</h4><p>Portable copy of every record</p></div><button class="button small primary" id="reportBackup">Download</button></div><div class="report-option"><div class="report-icon">↺</div><div><h4>Restore backup</h4><p>Replace this device's records from JSON</p></div><label class="button small primary file-label">Choose file<input id="reportRestore" type="file" accept="application/json"></label></div></div><div style="margin-top:18px" class="card"><div class="card-head"><div><h3>Data overview</h3><p>Current browser storage</p></div></div><div class="summary-strip" style="margin:18px;border:0">${summary('Members',state.members.length)}${summary('Activities',state.activities.length)}${summary('Schedules & rosters',state.schedules.length+state.rosters.length)}${summary('Designs',state.designs.length)}</div></div>`}}
