views.dashboard=()=>originalDashboard().replace(`<div class="card-body quick-actions"><button class="quick-action" data-add="member"><span>＋ Add member</span><small>Grow the directory</small></button><button class="quick-action" data-add="activity"><span>＋ Plan activity</span><small>Meeting or training</small></button><button class="quick-action" data-add="design"><span>＋ Add design</span><small>Track creative work</small></button></div>`,`<div class="card-body quick-actions"><button class="quick-action" data-add="member"><span>＋ Add member</span><small>Grow the directory</small></button><button class="quick-action" data-add="activity"><span>＋ Schedule activity</span><small>Add to the calendar</small></button><button class="quick-action" data-add="contribution"><span>＋ Add contribution</span><small>Create a collection</small></button><button class="quick-action" data-add="payment"><span>＋ Record payment</span><small>Update contribution progress</small></button><button class="quick-action" data-add="design"><span>＋ Add design</span><small>Track creative work</small></button><button class="quick-action" data-page-jump="schedule"><span>✎ Edit schedule</span><small>Agenda and work roster</small></button></div>`)+contributionProgress('Dashboard contribution progress');
views.members=()=>`${tools('Search members…','member',['All status','Active','Inactive'])}<div class="card"><div class="card-head"><div><h3>Member directory</h3><p>${state.members.length} people recorded</p></div><button class="button small ghost right" id="csvMembers">↓ CSV export</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Member</th><th>Contact</th><th>Sub-unit</th><th>Birthday</th><th>Skill level</th><th>Status</th><th></th></tr></thead><tbody>${state.members.map(x=>`<tr data-search="${esc(Object.values(x).join(' ').toLowerCase())}" data-status="${x.status}"><td><div class="person"><span class="person-badge">${initials(x.name)}</span><div><strong>${esc(x.name)}</strong><small>${esc(x.email)}</small></div></div></td><td>${esc(x.phone)}</td><td>${esc(x.subunit)}</td><td>${dateFmt(x.birthday,{day:'numeric',month:'short'})}</td><td><strong>${esc(x.skill||'—')}</strong><br><small>${esc(x.skillLevel||'—')}</small></td><td><span class="pill ${x.status.toLowerCase()}">${x.status}</span></td>${rowActions('member',x.id)}</tr>`).join('')}</tbody></table></div></div><div style="margin-top:18px">${skillsCard()}</div>`;
views.contributions=()=>`${contributionProgress('Contribution progress')}<div class="page-tools"><button class="button primary" data-add="contribution">＋ Contribution type</button><button class="button gold" data-add="payment">＋ Record payment</button></div><div class="card"><div class="card-head"><div><h3>Individual contributions</h3><p>Expected amount and collection progress for each contribution</p></div></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Contribution</th><th>Per member</th><th>Expected</th><th>Received</th><th>Outstanding</th><th>Progress</th><th></th></tr></thead><tbody>${state.contributionTypes.map(c=>{let got=state.payments.filter(p=>p.typeId===c.id).reduce((s,p)=>s+Number(p.amount),0),exp=Number(c.amount)*state.members.length,pc=exp?Math.round(got/exp*100):0;return `<tr><td><strong>${esc(c.name)}</strong><br><small>Due ${dateFmt(c.due)}</small></td><td>${money(c.amount)}</td><td>${money(exp)}</td><td>${money(got)}</td><td>${money(exp-got)}</td><td>${pc}%<div class="progress"><i style="width:${Math.min(pc,100)}%"></i></div></td>${rowActions('contribution',c.id)}</tr>`}).join('')||`<tr><td colspan="7">${empty('No contribution types')}</td></tr>`}</tbody></table></div></div>`;
