views.designs=()=>`${tools('Search designs…','design',['All status','Pending','Close to post date','Past'])}<div class="design-grid">${state.designs.map(x=>{let status=designStatus(x),title=x.memberId?memberName(x.memberId):x.title;return `<article class="design-card" data-search="${esc(Object.values(x).join(' ').toLowerCase())}" data-status="${status}"><div class="design-thumb"><span>${esc(x.category)}</span></div><div class="design-info"><span class="pill ${status.toLowerCase().replaceAll(' ','-')}">${status}</span><h4>${esc(title||'Untitled design')}</h4><p>${dateFmt(x.date)} · ${esc(x.category)}</p><div class="actions"><a class="button small ghost" href="${esc(x.canva||'#')}" target="_blank" rel="noopener">Open Canva</a><button class="button small" data-edit="design" data-id="${x.id}">Edit</button><button class="button small danger" data-delete="design" data-id="${x.id}">Delete</button></div></div></article>`}).join('')||empty('No designs yet')}</div>`;
function contributionProgress(title){return `<section class="card" style="margin:18px 0"><div class="card-head"><div><h3>${title}</h3><p>Each contribution is measured independently</p></div></div><div class="contribution-metrics">${state.contributionTypes.map(c=>{let exp=Number(c.amount)*state.members.length,got=state.payments.filter(p=>p.typeId===c.id).reduce((s,p)=>s+Number(p.amount),0),pc=exp?Math.round(got/exp*100):0;return `<div class="contribution-stat"><span>${esc(c.name)}</span><strong>${pc}%</strong><small>${money(got)} of ${money(exp)}</small><div class="progress"><i style="width:${Math.min(pc,100)}%"></i></div></div>`}).join('')||empty('Add a contribution to see its progress')}</div></section>`}
function calendarView(){let types=['All','Training','Outreach','Event','Evangelism','Meeting','Hangout'],filtered=state.activities.filter(a=>activityTypeFilter==='All'||a.type===activityTypeFilter),y=calendarDate.getFullYear(),m=calendarDate.getMonth(),first=new Date(y,m,1),days=new Date(y,m+1,0).getDate(),offset=first.getDay(),cells=[];for(let i=0;i<offset;i++)cells.push('<div class="calendar-day muted"></div>');for(let d=1;d<=days;d++){let iso=`${y}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`,items=state.activities.filter(a=>a.date===iso);cells.push(`<button class="calendar-day" data-calendar-date="${iso}"><b>${d}</b>${items.map(a=>`<span>${esc(a.time)} ${esc(a.title)}</span>`).join('')}<i>＋ Schedule</i></button>`)}return `<div class="calendar-toolbar"><select class="filter" id="activityTypeFilter">${types.map(t=>`<option ${t===activityTypeFilter?'selected':''}>${t}</option>`).join('')}</select><span class="spacer"></span><button class="button primary" data-add="activity">＋ Add activity</button></div><div class="card activity-results"><div class="card-head"><div><h3>${activityTypeFilter} activities</h3><p>${filtered.length} matching result${filtered.length===1?'':'s'}</p></div></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Activity</th><th>Type</th><th>Date & time</th><th>Venue</th><th>Status</th><th></th></tr></thead><tbody>${filtered.sort((a,b)=>a.date.localeCompare(b.date)).map(a=>`<tr><td><strong>${esc(a.title)}</strong></td><td>${esc(a.type)}</td><td>${dateFmt(a.date)} · ${esc(a.time)}</td><td>${esc(a.venue)}</td><td><span class="pill ${a.status.toLowerCase().replace(' ','-')}">${a.status}</span></td>${rowActions('activity',a.id)}</tr>`).join('')||`<tr><td colspan="6">${empty('No matching activities')}</td></tr>`}</tbody></table></div></div><div class="calendar-toolbar calendar-heading"><button class="button ghost" data-calendar-nav="-1">←</button><h2>${first.toLocaleDateString('en-NG',{month:'long',year:'numeric'})}</h2><button class="button ghost" data-calendar-nav="1">→</button></div><div class="calendar"><div class="calendar-weekdays">${['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(x=>`<span>${x}</span>`).join('')}</div><div class="calendar-grid">${cells.join('')}</div></div>`}
function templateView(){let s=state.schedules[0]||{id:id('s'),title:'Meeting Agenda',date:'',time:'',venue:'',coordinator:'',theme:'',notes:'',agenda:''},r=state.rosters[0]||{id:id('r'),event:'Work Roster',date:'',venue:'',coordinator:'',notes:'',assignments:''};if(!state.schedules.length)state.schedules.push(s);if(!state.rosters.length)state.rosters.push(r);return `<div class="template-stack">${editableTemplate('schedule',s)}${editableTemplate('roster',r)}</div>`}
function editableTemplate(type,x){if(type==='roster')return displayScheduleTemplate(x);let rows=parseRows(x.agenda,6),heads=['Start','End','Activity','Description','Responsible','Notes'];while(rows.length<4)rows.push(Array(heads.length).fill(''));return `<section class="card editable-template" data-template="${type}" data-id="${x.id}"><div class="card-head"><div><p class="eyebrow">EDITABLE MEETING TEMPLATE</p><h3 contenteditable="true" data-key="title">${esc(x.title)}</h3></div><div class="right"><button class="button small ghost" data-export="${type}" data-id="${x.id}">Export</button><button class="button small primary" data-save-template="${type}">Save template</button></div></div><div class="card-body"><div class="template-meta">${[['date','Date'],['venue','Venue'],['coordinator','Coordinator'],['theme','Theme']].map(([k,l])=>`<label>${l}<input type="${k==='date'?'date':'text'}" data-key="${k}" value="${esc(x[k]||'')}"></label>`).join('')}</div><div class="table-wrap"><table class="data-table"><thead><tr>${heads.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${rows.map((row,ri)=>`<tr>${row.map((v,ci)=>`<td contenteditable="true" data-cell="${ri},${ci}">${esc(v)}</td>`).join('')}</tr>`).join('')}</tbody></table></div><label class="template-notes">Notes<textarea data-key="notes">${esc(x.notes||'')}</textarea></label></div></section>`}
function displayScheduleTemplate(x){let rows=parseRows(x.assignments,5);if(rows.length!==4||rows.some(r=>r.length!==5))rows=[['First Service','Praise & Choir Ministration','','',''],['First Service','Word','','',''],['Second Service','Praise & Choir Ministration','','',''],['Second Service','Word','','','']];return `<section class="display-schedule editable-template" data-template="roster" data-id="${x.id}"><div class="display-actions"><div><p>EDITABLE WORK SCHEDULE</p><h3 contenteditable="true" data-key="event">${esc(x.event||'Display Schedule')}</h3></div><div><button class="button small ghost" data-export="roster" data-id="${x.id}">Export portrait JPG / PDF</button><button class="button small gold" data-save-template="roster">Save schedule</button></div></div><label class="display-date">Schedule date <input type="date" data-key="date" value="${esc(x.date||'')}"></label><div class="display-table"><div class="display-head"><span>Service</span><span>Ministration</span><span>▣ Side Screen</span><span>▣ Middle Screen</span><span>▤ Scripture Assistance</span></div>${rows.map((row,ri)=>`<div class="display-row ${ri===2?'service-break':''}">${row.map((v,ci)=>`<span contenteditable="true" data-cell="${ri},${ci}">${esc(v)}</span>`).join('')}</div>`).join('')}</div><label class="display-notes">Notes<textarea data-key="notes">${esc(x.notes||'')}</textarea></label></section>`}
displayScheduleTemplate=function(x){let rows=parseRows(x.assignments,5),heads=['Service','Ministration','Side Screen','Middle Screen','Scripture Assistance'];if(rows.length!==4||rows.some(r=>r.length!==5))rows=[['First Service','Praise & Choir Ministration','','',''],['First Service','Word','','',''],['Second Service','Praise & Choir Ministration','','',''],['Second Service','Word','','','']];return `<section class="card editable-template work-template" data-template="roster" data-id="${x.id}"><div class="card-head"><div><p class="eyebrow">EDITABLE WORK SCHEDULE</p><h3 contenteditable="true" data-key="event">${esc(x.event||'Display Schedule')}</h3></div><div class="right"><button class="button small ghost" data-export="roster" data-id="${x.id}">Export portrait JPG / PDF</button><button class="button small primary" data-save-template="roster">Save schedule</button></div></div><div class="card-body"><div class="template-meta"><label>Date<input type="date" data-key="date" value="${esc(x.date||'')}"></label></div><div class="table-wrap"><table class="data-table schedule-table"><thead><tr>${heads.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${rows.map((row,ri)=>`<tr class="${ri===2?'service-break':''}">${row.map((v,ci)=>`<td contenteditable="true" data-cell="${ri},${ci}">${esc(v)}</td>`).join('')}</tr>`).join('')}</tbody></table></div><label class="template-notes">Notes<textarea data-key="notes">${esc(x.notes||'')}</textarea></label></div></section>`}
function saveTemplate(button){let box=button.closest('[data-template]'),type=box.dataset.template,col=collection(type),x=state[col].find(v=>v.id===box.dataset.id),fields=box.querySelectorAll('[data-key]');fields.forEach(el=>x[el.dataset.key]=el.value??el.textContent.trim());let rows=[...box.querySelectorAll('tbody tr')].map(tr=>[...tr.querySelectorAll('td')].map(td=>td.textContent.trim()).join('|')).filter(r=>r.replaceAll('|','').trim());x[type==='schedule'?'agenda':'assignments']=rows.join('\n');save('Template saved')}
function designStatus(x){let target=new Date((x.date||'2999-01-01')+'T23:59:59'),now=new Date(),days=Math.ceil((target-now)/86400000);return days<0?'Past':days<=3?'Close to post date':'Pending'}
const NOTIFICATION_READ_KEY='illuminate-read-notifications';
function notificationReadSet(){try{return new Set(JSON.parse(localStorage.getItem(NOTIFICATION_READ_KEY)||'[]'))}catch{return new Set()}}
function notificationCenterItems(){let now=new Date(),today=new Date(now.getFullYear(),now.getMonth(),now.getDate()),items=[];state.members.forEach(member=>{if(!member.birthday)return;let next=nextBirthday(member.birthday),days=Math.ceil((next-today)/86400000);if(days<=30)items.push({key:`birthday:${member.id}:${next.getFullYear()}`,type:'Birthday',title:`${member.name}'s birthday`,body:days===0?'Celebration is today':`Coming up in ${days} day${days===1?'':'s'}`,date:next,page:'members',icon:'♢'})});state.activities.forEach(activity=>{let date=new Date(activity.date+'T00:00:00'),days=Math.ceil((date-today)/86400000);if(days>=0&&days<=30)items.push({key:`activity:${activity.id}:${activity.date}`,type:activity.type,title:activity.title,body:`${dateFmt(activity.date)} · ${activity.time||'Time not set'} · ${activity.venue||'Venue not set'}`,date,page:'activities',icon:'◷'})});state.contributionTypes.forEach(item=>{if(!item.due||item.status!=='Active')return;let date=new Date(item.due+'T00:00:00'),days=Math.ceil((date-today)/86400000);if(days>=-7&&days<=14)items.push({key:`contribution:${item.id}:${item.due}`,type:'Contribution',title:item.name,body:days<0?`Deadline passed ${Math.abs(days)} day${Math.abs(days)===1?'':'s'} ago`:days===0?'Deadline is today':`Due in ${days} day${days===1?'':'s'}`,date,page:'contributions',icon:'₦'})});state.designs.forEach(design=>{if(!design.date)return;let date=new Date(design.date+'T00:00:00'),days=Math.ceil((date-today)/86400000),title=design.memberId?memberName(design.memberId):design.title;if(days>=-7&&days<=14)items.push({key:`design:${design.id}:${design.date}`,type:'Design',title:title||'Scheduled design',body:days<0?`Post date passed ${Math.abs(days)} day${Math.abs(days)===1?'':'s'} ago`:days===0?'Scheduled to post today':`Scheduled in ${days} day${days===1?'':'s'}`,date,page:'designs',icon:'◇'})});return items.sort((a,b)=>a.date-b.date)}
function updateNotificationBadge(){let count=document.getElementById('notificationCount');if(!count)return;let read=notificationReadSet(),unread=notificationCenterItems().filter(item=>!read.has(item.key)).length;count.textContent=unread>99?'99+':unread;count.hidden=unread===0}
function markNotificationRead(key){let read=notificationReadSet();read.add(key);localStorage.setItem(NOTIFICATION_READ_KEY,JSON.stringify([...read]));updateNotificationBadge()}
function markAllNotificationsRead(){localStorage.setItem(NOTIFICATION_READ_KEY,JSON.stringify(notificationCenterItems().map(item=>item.key)));render();toast('All notifications marked as read')}
views.notifications=()=>{let items=notificationCenterItems(),read=notificationReadSet();return `<div class="page-tools"><p class="notification-summary">Upcoming reminders and recent deadlines</p><span class="spacer"></span><button class="button ghost" id="markAllNotifications">Mark all as read</button></div><section class="card notification-page"><div class="card-head"><div><h3>Notification center</h3><p>${items.filter(item=>!read.has(item.key)).length} unread · ${items.length} total</p></div></div><div class="notification-list">${items.map(item=>`<button class="notification-item ${read.has(item.key)?'read':'unread'}" data-notification-key="${esc(item.key)}" data-notification-page="${item.page}"><span class="notification-type-icon">${item.icon}</span><span class="notification-copy"><small>${esc(item.type)}</small><strong>${esc(item.title)}</strong><span>${esc(item.body)}</span></span><time>${dateFmt(item.date.toISOString().slice(0,10),{day:'numeric',month:'short'})}</time></button>`).join('')||empty('You have no upcoming reminders')}</div></section>`}
views.designs=()=>`${tools('Search designs…','design',['All status','Pending','Close to post date','Past'])}<div class="design-grid">${state.designs.map(x=>{let status=designStatus(x),title=x.memberId?memberName(x.memberId):x.title;return `<article class="design-card" data-search="${esc(Object.values(x).join(' ').toLowerCase())}" data-status="${status}"><div class="design-thumb"><span>${esc(x.category)}</span></div><div class="design-info"><span class="pill ${status.toLowerCase().replaceAll(' ','-')}">${status}</span><h4>${esc(title||'Untitled design')}</h4><p>${dateFmt(x.date)} · ${esc(x.category)}</p><div class="design-file"><span>${x.fileName?'▣':'○'}</span><div><strong>${esc(x.fileName||'No file uploaded')}</strong><small>${x.fileSize?formatBytes(x.fileSize):'Edit this design to upload a file'}</small></div></div><div class="actions">${x.filePath?`<button class="button small gold" data-download-design="${x.id}">Download</button>`:''}<button class="button small" data-edit="design" data-id="${x.id}">Edit</button><button class="button small danger" data-delete="design" data-id="${x.id}">Delete</button></div></div></article>`}).join('')||empty('No designs yet')}</div>`;
function formatBytes(value){if(!value)return '';let units=['B','KB','MB','GB'],i=Math.min(Math.floor(Math.log(value)/Math.log(1024)),3);return `${(value/1024**i).toFixed(i?1:0)} ${units[i]}`}
function metric(a,b,c){return `<div class="metric"><span>${a}</span><strong>${b}</strong><small>${c}</small></div>`}function summary(a,b){return `<div class="summary-cell"><span>${a}</span><strong>${b}</strong></div>`}function empty(t){return `<div class="empty"><div class="empty-icon">◇</div>${t}</div>`}
function tools(ph,type,statuses){return `<div class="page-tools"><input class="search" id="searchInput" placeholder="${ph}" aria-label="${ph}"><select class="filter" id="statusFilter">${statuses.map(x=>`<option>${x}</option>`).join('')}</select><span class="spacer"></span><button class="button primary" data-add="${type}">＋ Add ${type}</button></div>`}
function rowActions(type,id){return `<td><div class="actions"><button class="action" data-edit="${type}" data-id="${id}">Edit</button><button class="action danger" data-delete="${type}" data-id="${id}">Delete</button></div></td>`}
function recordItem(x,type,label,date,venue,title=x.title){return `<div class="list-item"><div class="date-tile"><b>${dateFmt(date,{month:'short'}).toUpperCase()}</b><strong>${new Date(date+'T00:00:00').getDate()}</strong></div><div class="grow"><strong>${esc(title)}</strong><small>${label} · ${esc(venue)}</small></div><div class="actions"><button class="button small ghost" data-export="${type}" data-id="${x.id}">Export</button><button class="action" data-edit="${type}" data-id="${x.id}">Edit</button><button class="action danger" data-delete="${type}" data-id="${x.id}">Delete</button></div></div>`}
function skillsCard(){let names=['General schedule','Scripture Projection','using VMIX'],levels=['Beginner','Intermediate','Advanced'];return `<div class="card"><div class="card-head"><div><h3>Skill matrix</h3><p>Members by approved skill and level</p></div></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Skill</th>${levels.map(l=>`<th>${l}</th>`).join('')}<th>Total</th></tr></thead><tbody>${names.map(skill=>{let ms=state.members.filter(m=>m.skill===skill);return `<tr><td><strong>${skill}</strong></td>${levels.map(l=>`<td>${ms.filter(m=>m.skillLevel===l).length}</td>`).join('')}<td><strong>${ms.length}</strong></td></tr>`}).join('')}</tbody></table></div></div>`}
function bindView(){document.querySelectorAll('[data-add]').forEach(b=>b.onclick=()=>openForm(b.dataset.add));document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>openForm(b.dataset.edit,b.dataset.id));document.querySelectorAll('[data-delete]').forEach(b=>b.onclick=()=>remove(b.dataset.delete,b.dataset.id));document.querySelectorAll('[data-page-jump]').forEach(b=>b.onclick=()=>{current=b.dataset.pageJump;render()});document.querySelectorAll('[data-export]').forEach(b=>b.onclick=()=>exportRecord(b.dataset.export,b.dataset.id));document.querySelectorAll('[data-report]').forEach(b=>b.onclick=()=>printDashboard());document.querySelectorAll('[data-calendar-date]').forEach(b=>b.onclick=()=>{openForm('activity');document.querySelector('[name="date"]').value=b.dataset.calendarDate});document.querySelectorAll('[data-calendar-nav]').forEach(b=>b.onclick=()=>{calendarDate.setMonth(calendarDate.getMonth()+Number(b.dataset.calendarNav));render()});document.querySelectorAll('[data-save-template]').forEach(b=>b.onclick=()=>saveTemplate(b));let atf=document.getElementById('activityTypeFilter');if(atf)atf.onchange=()=>{activityTypeFilter=atf.value;render()};let s=document.getElementById('searchInput'),f=document.getElementById('statusFilter');if(s)s.oninput=filterRows;if(f)f.onchange=filterRows;document.querySelectorAll('#csvMembers').forEach(b=>b.onclick=csvMembers);let rb=document.getElementById('reportBackup');if(rb)rb.onclick=backup;let rr=document.getElementById('reportRestore');if(rr)rr.onchange=restore}
function filterRows(){let q=(document.getElementById('searchInput')?.value||'').toLowerCase(),f=document.getElementById('statusFilter')?.value||'All status';document.querySelectorAll('[data-search]').forEach(r=>r.style.display=(r.dataset.search.includes(q)&&(f==='All status'||r.dataset.status===f))?'':'none')}
const schemas={member:[['name','Name','text'],['phone','Phone','tel'],['email','Email','email'],['birthday','Birthday','date'],['status','Status','select','Active|Inactive'],['role','Role','text'],['subunit','Sub-unit','text'],['skills','Skills and levels','text','e.g. Canva:Advanced, Photography:Intermediate'],['functions','Functions','text'],['trainings','Trainings','text'],['notes','Notes','textarea']],contribution:[['name','Contribution name','text'],['amount','Expected amount per member (₦)','number'],['due','Due date','date'],['status','Status','select','Active|Closed']],payment:[['typeId','Contribution','selectType'],['memberId','Member','selectMember'],['amount','Amount paid (₦)','number'],['date','Payment date','date']],activity:[['title','Activity title','text'],['type','Type','select','Meeting|Training|Outreach|Event'],['date','Date','date'],['time','Time','time'],['venue','Venue','text'],['coordinator','Coordinator','text'],['status','Status','select','Planned|In Progress|Completed'],['notes','Notes','textarea']],schedule:[['title','Meeting title','text'],['date','Date','date'],['time','Time','time'],['venue','Venue','text'],['coordinator','Coordinator','text'],['theme','Theme','text'],['agenda','Agenda items','textarea','One item per line: Start|End|Activity|Description|Responsible|Notes'],['notes','General notes','textarea']],roster:[['event','Event title','text'],['date','Date','date'],['venue','Venue','text'],['coordinator','Coordinator','text'],['assignments','Duty assignments','textarea','One per line: Function|Member|Backup|Reporting time|Duty time|Location|Status|Notes'],['notes','General notes','textarea']],design:[['title','Design title','text'],['category','Category','select','Birthday|Wedding Anniversary|Event|Announcement|Other'],['date','Scheduled date','date'],['person','Person / celebration','text'],['canva','Canva link','url'],['thumbnail','Thumbnail image link','url'],['status','Status','select','Pending|In Progress|Approved'],['notes','Notes','textarea']]};
schemas.member=[['name','Name','text'],['phone','Phone','tel'],['email','Email','email'],['birthday','Birthday','date'],['status','Status','select','Active|Inactive'],['subunit','Sub-unit','select','Finance|Admin|Technical|Member|Welfare'],['skill','Skill','select','General schedule|Scripture Projection|using VMIX'],['skillLevel','Skill level','select','Beginner|Intermediate|Advanced'],['notes','Notes','textarea']];
schemas.activity=[['title','Activity title','text'],['type','Type','select','Training|Outreach|Event|Evangelism|Meeting|Hangout'],['date','Date','date'],['time','Time','time'],['venue','Venue','text'],['coordinator','Coordinator','text'],['status','Status','select','Planned|In Progress|Completed'],['notes','Notes','textarea']];
schemas.design=[['memberId','Member (optional)','selectMemberOptional'],['title','Title when not for a member','text'],['category','Category','select','Birthday|Wedding Anniversary|Event|Announcement|Other'],['date','Scheduled / design date','date'],['file','Design file','file','Upload JPG, PNG, PDF, or another finished design file (maximum 50 MB).'],['notes','Notes','textarea']];
function collection(type){return type==='contribution'?'contributionTypes':type==='payment'?'payments':type==='activity'?'activities':type==='schedule'?'schedules':type==='roster'?'rosters':type==='design'?'designs':'members'}
function openForm(type,recordId){let data=recordId?state[collection(type)].find(x=>x.id===recordId):{};editContext={type,recordId};document.getElementById('modalEyebrow').textContent=recordId?'EDIT RECORD':'NEW RECORD';document.getElementById('modalTitle').textContent=`${recordId?'Edit':'Add'} ${type}`;document.getElementById('modalBody').innerHTML=`<div class="form-grid">${schemas[type].map(([n,l,t,opt])=>field(n,l,t,data[n]??'',opt)).join('')}</div>`;document.getElementById('modal').showModal()}
function field(n,l,t,v,opt){let input=t==='textarea'?`<textarea name="${n}" ${n==='agenda'||n==='assignments'?'rows="7"':''}>${esc(v)}</textarea>`:t==='select'?`<select name="${n}">${opt.split('|').map(o=>`<option ${o===v?'selected':''}>${o}</option>`).join('')}</select>`:t==='selectMember'?`<select name="${n}">${state.members.map(m=>`<option value="${m.id}" ${m.id===v?'selected':''}>${esc(m.name)}</option>`).join('')}</select>`:t==='selectMemberOptional'?`<select name="${n}"><option value="">Not for a member</option>${state.members.map(m=>`<option value="${m.id}" ${m.id===v?'selected':''}>${esc(m.name)}</option>`).join('')}</select>`:t==='selectType'?`<select name="${n}">${state.contributionTypes.map(c=>`<option value="${c.id}" ${c.id===v?'selected':''}>${esc(c.name)}</option>`).join('')}</select>`:t==='file'?`<input name="${n}" type="file" accept="image/*,.pdf,.zip,.ppt,.pptx,.psd,.ai,.svg">`:`<input name="${n}" type="${t}" value="${esc(v)}" ${n==='name'?'required':''}>`;return `<div class="field ${t==='textarea'||t==='file'?'full':''}"><label>${l}</label>${input}${opt&&t!=='select'?`<span class="hint">${opt}</span>`:''}</div>`}
function storagePath(path){return String(path).split('/').map(encodeURIComponent).join('/')}
async function uploadDesignFile(file){if(!cloudSession)throw new Error('Sign in before uploading a design');if(file.size>52428800)throw new Error('The file is larger than 50 MB');let safe=file.name.replace(/[^a-zA-Z0-9._,'!&$@=;()+?-]+/g,'-'),path=`${new Date().toISOString().slice(0,10)}/${Date.now()}-${safe}`,response=await fetch(`${SUPABASE_URL}/storage/v1/object/design-files/${storagePath(path)}`,{method:'POST',headers:{'apikey':SUPABASE_KEY,'Authorization':`Bearer ${cloudSession.access_token}`,'Content-Type':file.type||'application/octet-stream','x-upsert':'false'},body:file});if(!response.ok){let data=await response.json().catch(()=>({}));throw new Error(data.message||data.error||'File upload failed')}return {filePath:path,fileName:file.name,fileType:file.type||'application/octet-stream',fileSize:file.size}}
async function downloadDesignFile(recordId){let design=state.designs.find(x=>x.id===recordId);if(!design?.filePath){toast('No file has been uploaded for this design');return}try{let response=await fetch(`${SUPABASE_URL}/storage/v1/object/authenticated/design-files/${storagePath(design.filePath)}`,{headers:{'apikey':SUPABASE_KEY,'Authorization':`Bearer ${cloudSession.access_token}`}});if(!response.ok)throw new Error('Download failed');let blob=await response.blob(),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=design.fileName||'design-file';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000);toast('Design file downloaded')}catch(error){toast(error.message)}}
