document.getElementById('modalForm').addEventListener('submit',async e=>{if(e.submitter?.value==='cancel')return;e.preventDefault();let button=document.getElementById('modalSave'),formData=new FormData(e.currentTarget),file=formData.get('file'),fd=Object.fromEntries(formData);delete fd.file;button.disabled=true;button.textContent=file?.size?'Uploading…':'Saving…';try{let col=collection(editContext.type),existing=editContext.recordId?state[col].find(x=>x.id===editContext.recordId):null;if(editContext.type==='design'&&file?.size){let uploaded=await uploadDesignFile(file);if(existing?.filePath)deleteDesignFile(existing.filePath);Object.assign(fd,uploaded)}if(editContext.recordId){let i=state[col].findIndex(x=>x.id===editContext.recordId);state[col][i]={...state[col][i],...fd}}else state[col].push({id:id(editContext.type[0]),...fd});document.getElementById('modal').close();save(file?.size?'File uploaded and design saved':'Record saved')}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent='Save record'}});
function remove(type,recordId){if(!confirm('Delete this record? This cannot be undone unless you have a backup.'))return;let col=collection(type),record=state[col].find(x=>x.id===recordId);if(type==='design'&&record?.filePath)deleteDesignFile(record.filePath);state[col]=state[col].filter(x=>x.id!==recordId);if(type==='member')state.payments=state.payments.filter(x=>x.memberId!==recordId);if(type==='contribution')state.payments=state.payments.filter(x=>x.typeId!==recordId);save('Record deleted')}
function nextBirthday(v){if(!v)return new Date(2999,0,1);let d=new Date(v+'T00:00:00'),now=new Date(),n=new Date(now.getFullYear(),d.getMonth(),d.getDate());if(n<new Date(now.getFullYear(),now.getMonth(),now.getDate()))n.setFullYear(n.getFullYear()+1);return n}function daysUntil(d){return Math.max(0,Math.ceil((d-new Date())/86400000))}function memberName(x){return state.members.find(m=>m.id===x)?.name||'Unknown'}function typeName(x){return state.contributionTypes.find(c=>c.id===x)?.name||'Unknown'}
