function csvMembers(){let cols=['Name','Phone','Email','Birthday','Status','Sub-unit','Skill','Skill Level','Notes'],keys=['name','phone','email','birthday','status','subunit','skill','skillLevel','notes'],q=v=>'"'+String(v??'').replace(/"/g,'""')+'"';download(`illuminate-members-${new Date().toISOString().slice(0,10)}.csv`,[cols.map(q).join(','),...state.members.map(m=>keys.map(k=>q(m[k])).join(','))].join('\r\n'),'text/csv;charset=utf-8');toast('Members CSV downloaded')}
function exportRecord(type,recordId){if(type==='roster'){exportDisplaySchedule(recordId);return}let x=state[collection(type)].find(v=>v.id===recordId),title=x.title,rows=parseRows(x.agenda,6),heads=['Start','End','Activity','Description','Responsible','Notes'];let html=`<!doctype html><html><head><title>${esc(title)}</title><style>@page{size:A4 portrait;margin:12mm}body{font-family:Arial;color:#172a46;padding:10px}header{border-bottom:3px solid #d7a928;margin-bottom:16px}small{letter-spacing:2px}h1{font-family:Georgia}table{border-collapse:collapse;width:100%;font-size:9px;table-layout:fixed}th,td{border:1px solid #cad2dc;padding:7px 5px;text-align:left;overflow-wrap:anywhere}th{background:#172a46;color:white}.meta{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin:14px 0;font-size:11px}.notes{margin-top:16px;padding:10px;background:#f4f6f8}.no-print{margin-bottom:15px}@media print{.no-print{display:none}}</style></head><body><button class="no-print" onclick="print()">Print / Save PDF</button><header><small>DAVID'S CHRISTIAN CENTER · ILLUMINATE DEPARTMENT</small><h1>${esc(title)}</h1></header><div class="meta"><b>Date: ${dateFmt(x.date)}</b><b>Venue: ${esc(x.venue)}</b><b>Coordinator: ${esc(x.coordinator)}</b><b>Theme: ${esc(x.theme||'—')}</b></div><table><thead><tr>${heads.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${heads.map((_,i)=>`<td>${esc(r[i]||'')}</td>`).join('')}</tr>`).join('')}</tbody></table><div class="notes"><b>Notes</b><p>${esc(x.notes||'No additional notes.')}</p></div></body></html>`;let win=open('','_blank');win.document.write(html);win.document.close();setTimeout(()=>win.print(),350);renderCanvasExport(title,x,heads,rows)}
function exportDisplaySchedule(recordId){let x=state.rosters.find(v=>v.id===recordId),rows=parseRows(x.assignments,5),html=`<!doctype html><html><head><title>${esc(x.event||'Display Schedule')}</title><style>@page{size:A4 portrait;margin:0}*{box-sizing:border-box}body{margin:0;background:#090909;color:#fff;font-family:Arial;padding:12mm;min-height:297mm}button{padding:9px 13px;margin-bottom:10px}.title{text-align:center;margin:8mm 0 4mm}.title h1{font:italic 44px Georgia;margin:0}.title h2{font-size:27px;margin:7px 0}.box{border:1.5px solid #fff;border-radius:24px;overflow:hidden;margin-top:8mm}.grid{display:grid;grid-template-columns:1.05fr 1.45fr 1fr 1fr 1.15fr}.grid span{padding:13px 8px;border-right:2px solid #f4c400;text-align:center;min-height:52px;display:grid;place-items:center}.grid span:last-child{border-right:0}.head{color:#f4c400;font-weight:bold}.row{border-top:1px solid #fff}.row span:first-child{color:#f4c400;font-weight:bold}.break{border-top:2px solid #fff}.notes{margin:8mm 2mm;color:#ddd}@media print{button{display:none}}</style></head><body><button onclick="print()">Print / Save PDF</button><div class="title"><h1>${esc(x.event||'Display Schedule')}</h1><h2>${dateFmt(x.date,{day:'numeric',month:'long',year:'numeric'})}</h2></div><div class="box"><div class="grid head"><span>Service</span><span>Ministration</span><span>▣ Side Screen</span><span>▣ Middle Screen</span><span>▤ Scripture Assistance</span></div>${rows.map((r,i)=>`<div class="grid row ${i===2?'break':''}">${r.map(v=>`<span>${esc(v)}</span>`).join('')}</div>`).join('')}</div>${x.notes?`<div class="notes">${esc(x.notes)}</div>`:''}</body></html>`;let win=open('','_blank');win.document.write(html);win.document.close();setTimeout(()=>win.print(),350);renderDisplayScheduleJpg(x,rows)}
function renderDisplayScheduleJpg(x,rows){let c=document.createElement('canvas'),w=1200,h=1600,g=c.getContext('2d');c.width=w;c.height=h;g.fillStyle='#080808';g.fillRect(0,0,w,h);g.strokeStyle='#f4c400';g.lineWidth=2;for(let i=-200;i<w;i+=150){g.beginPath();g.moveTo(i,0);g.lineTo(i+500,h);g.strokeStyle='rgba(244,196,0,.055)';g.stroke()}g.textAlign='center';g.fillStyle='#fff';g.font='italic 74px Georgia';g.fillText(x.event||'Display Schedule',w/2,145);g.font='bold 42px Arial';g.fillText(dateFmt(x.date,{day:'numeric',month:'long',year:'numeric'}),w/2,215);let left=65,top=290,width=1070,colW=[190,300,190,190,200],rowH=150;g.strokeStyle='#fff';g.lineWidth=3;g.strokeRect(left,top,width,rowH*5);let xx=left;for(let i=0;i<4;i++){xx+=colW[i];g.strokeStyle='#f4c400';g.beginPath();g.moveTo(xx,top);g.lineTo(xx,top+rowH*5);g.stroke()}for(let i=1;i<5;i++){g.strokeStyle='#fff';g.beginPath();g.moveTo(left,top+i*rowH);g.lineTo(left+width,top+i*rowH);g.stroke()}let heads=['Service','Ministration','Side Screen','Middle Screen','Scripture Assistance'];xx=left;g.font='bold 20px Arial';heads.forEach((v,i)=>{g.fillStyle='#f4c400';wrapCanvas(g,v,xx+colW[i]/2,top+55,colW[i]-12,24);xx+=colW[i]});rows.forEach((r,ri)=>{xx=left;r.forEach((v,i)=>{g.fillStyle=i===0?'#f4c400':'#fff';g.font=`${i===0?'bold ':''}22px Arial`;wrapCanvas(g,v,xx+colW[i]/2,top+(ri+1)*rowH+48,colW[i]-16,28);xx+=colW[i]})});g.fillStyle='#ddd';g.font='18px Arial';g.textAlign='left';g.fillText((x.notes||'').slice(0,95),left,top+rowH*5+65);c.toBlob(b=>download(`${slug(x.event||'display-schedule')}.jpg`,b,'image/jpeg'),'image/jpeg',.94);toast('Display schedule JPG downloaded; use the print window for PDF')}
function wrapCanvas(g,text,x,y,maxWidth,lineHeight){let words=String(text||'').split(' '),line='',lines=[];for(let word of words){let test=line+word+' ';if(g.measureText(test).width>maxWidth&&line){lines.push(line.trim());line=word+' '}else line=test}lines.push(line.trim());lines.slice(0,3).forEach((l,i)=>g.fillText(l,x,y+i*lineHeight))}
