function renderCanvasExport(title,x,heads,rows){let w=1200,rowH=64,pad=55,h=Math.max(1680,315+(rows.length+1)*rowH+150),c=document.createElement('canvas');c.width=w;c.height=h;let g=c.getContext('2d');g.fillStyle='#fff';g.fillRect(0,0,w,h);g.fillStyle='#172a46';g.fillRect(0,0,w,34);g.fillStyle='#d7a928';g.fillRect(0,34,w,8);g.fillStyle='#172a46';g.font='bold 17px Arial';g.fillText("DAVID'S CHRISTIAN CENTER · ILLUMINATE DEPARTMENT",pad,92);g.font='bold 39px Georgia';g.fillText(title.slice(0,42),pad,150);g.font='18px Arial';g.fillText(`Date: ${dateFmt(x.date)}   Venue: ${x.venue}`.slice(0,92),pad,202);g.fillText(`Coordinator: ${x.coordinator}`.slice(0,92),pad,234);let y=275,col=(w-pad*2)/heads.length;g.font='bold 12px Arial';heads.forEach((v,i)=>{g.fillStyle='#172a46';g.fillRect(pad+i*col,y,col,rowH);g.fillStyle='#fff';g.fillText(v.slice(0,15),pad+i*col+5,y+36)});y+=rowH;g.font='11px Arial';rows.forEach(r=>{r.forEach((v,i)=>{g.strokeStyle='#cdd4dd';g.strokeRect(pad+i*col,y,col,rowH);g.fillStyle='#172235';g.fillText(String(v||'').slice(0,18),pad+i*col+5,y+36)});y+=rowH});g.font='15px Arial';g.fillText(`Notes: ${x.notes||'No additional notes.'}`.slice(0,125),pad,y+48);c.toBlob(b=>download(`${slug(title)}.jpg`,b,'image/jpeg'),'image/jpeg',.92);toast('Portrait JPG downloaded; use the print window to save PDF')}
function printDashboard(){let m=metrics(),rows=state.contributionTypes.map(c=>{let exp=Number(c.amount)*state.members.length,got=state.payments.filter(p=>p.typeId===c.id).reduce((s,p)=>s+Number(p.amount),0);return `<tr><td>${esc(c.name)}</td><td>${money(exp)}</td><td>${money(got)}</td><td>${money(exp-got)}</td><td>${exp?Math.round(got/exp*100):0}%</td></tr>`}).join(''),levels=['Beginner','Intermediate','Advanced'],skillRows=['General schedule','Scripture Projection','using VMIX'].map(skill=>`<tr><td>${skill}</td>${levels.map(level=>`<td>${state.members.filter(x=>x.skill===skill&&x.skillLevel===level).length}</td>`).join('')}<td><b>${state.members.filter(x=>x.skill===skill).length}</b></td></tr>`).join(''),html=`<!doctype html><html><head><title>Illuminate Dashboard Report</title><style>@page{size:A4 portrait;margin:16mm}body{font-family:Arial;color:#172a46}header{border-bottom:3px solid #d7a928;margin-bottom:24px}h1,h2{font-family:Georgia}.metrics{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.metric{border:1px solid #dfe4ea;padding:15px}.metric b{display:block;font-size:25px;margin-top:7px}table{width:100%;border-collapse:collapse;margin-top:12px}th,td{border:1px solid #dfe4ea;padding:9px;text-align:left;font-size:11px}th{background:#172a46;color:#fff}.no-print{margin-bottom:15px}@media print{.no-print{display:none}}</style></head><body><button class="no-print" onclick="print()">Print / Save PDF</button><header><small>DAVID'S CHRISTIAN CENTER · ILLUMINATE DEPARTMENT</small><h1>Dashboard Report</h1><p>${new Date().toLocaleDateString('en-NG',{dateStyle:'long'})}</p></header><div class="metrics"><div class="metric">Total members<b>${state.members.length}</b></div><div class="metric">Active members<b>${m.active}</b></div><div class="metric">Inactive members<b>${m.inactive}</b></div><div class="metric">Active contributions<b>${state.contributionTypes.filter(c=>c.status==='Active').length}</b></div><div class="metric">Trainings<b>${m.training}</b></div></div><h2>Contribution progress</h2><table><thead><tr><th>Contribution</th><th>Expected</th><th>Received</th><th>Outstanding</th><th>Progress</th></tr></thead><tbody>${rows}</tbody></table><h2>Skill matrix</h2><table><thead><tr><th>Skill</th>${levels.map(x=>`<th>${x}</th>`).join('')}<th>Total</th></tr></thead><tbody>${skillRows}</tbody></table></body></html>`;let win=open('','_blank');win.document.write(html);win.document.close();setTimeout(()=>win.print(),350)}function slug(s){return s.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')}
function supabaseHeaders(token=cloudSession?.access_token){return {'apikey':SUPABASE_KEY,'Authorization':`Bearer ${token||SUPABASE_KEY}`,'Content-Type':'application/json'}}
async function authRequest(path,body){let response=await fetch(`${SUPABASE_URL}/auth/v1/${path}`,{method:'POST',headers:{'apikey':SUPABASE_KEY,'Content-Type':'application/json'},body:JSON.stringify(body)}),data=await response.json();if(!response.ok)throw new Error(data.msg||data.message||data.error_description||'Authentication failed');return data}
function storeSession(session){cloudSession=session;localStorage.setItem(SESSION_KEY,JSON.stringify(session));let email=session?.user?.email||'';document.getElementById('accountEmail').textContent=email;document.getElementById('accountButton').textContent=email?email.slice(0,2).toUpperCase():'IA'}
async function refreshCloudSession(){if(!cloudSession?.refresh_token)return false;try{let data=await authRequest('token?grant_type=refresh_token',{refresh_token:cloudSession.refresh_token});storeSession(data);return true}catch{return false}}
async function cloudFetch(path,options={}){let response=await fetch(`${SUPABASE_URL}/rest/v1/${path}`,{...options,headers:{...supabaseHeaders(),...(options.headers||{})}});if(response.status===401&&await refreshCloudSession())return cloudFetch(path,options);let text=await response.text(),data=null;if(text){try{data=JSON.parse(text)}catch{data=text}}if(!response.ok)throw new Error(data?.message||data?.hint||(typeof data==='string'&&data)||`Supabase request failed (${response.status})`);return data}
async function pullCloud(showMessage=false){if(!cloudSession)return;try{let rows=await cloudFetch('app_modules?select=module,records,updated_at&order=module');if(!rows.length){await pushCloud(true);return}let newest=rows.reduce((max,row)=>row.updated_at>max?row.updated_at:max,'');if(newest===lastCloudUpdate)return;rows.forEach(row=>{if(CLOUD_MODULES.includes(row.module)&&Array.isArray(row.records))state[row.module]=row.records});lastCloudUpdate=newest;localStorage.setItem(STORAGE_KEY,JSON.stringify(state));cloudReady=true;document.getElementById('lastSaved').textContent='Shared workspace synced';document.getElementById('cloudStatus').textContent=`Shared workspace synced · ${new Date().toLocaleTimeString('en-NG',{hour:'2-digit',minute:'2-digit'})}`;render();if(showMessage)toast('Shared data loaded')}catch(error){document.getElementById('lastSaved').textContent='Offline copy active';document.getElementById('cloudStatus').textContent=`Sync paused: ${error.message}`}}
async function pushCloud(initial=false){if(!cloudSession)return;clearTimeout(cloudWriteTimer);try{let rows=CLOUD_MODULES.map(module=>({module,records:state[module]||[],updated_by:cloudSession.user.id}));let result=await cloudFetch('app_modules?on_conflict=module',{method:'POST',headers:{'Prefer':'resolution=merge-duplicates,return=representation'},body:JSON.stringify(rows)});lastCloudUpdate=(result||[]).reduce((max,row)=>row.updated_at>max?row.updated_at:max,lastCloudUpdate);cloudReady=true;document.getElementById('lastSaved').textContent='Shared workspace synced';document.getElementById('cloudStatus').textContent='All modules are synchronized';if(initial)toast('Existing browser data migrated to Supabase')}catch(error){document.getElementById('lastSaved').textContent='Saved offline · sync pending';document.getElementById('cloudStatus').textContent=`Local changes are safe. Sync error: ${error.message}`}}
function queueCloudSync(){if(!cloudSession)return;clearTimeout(cloudWriteTimer);cloudWriteTimer=setTimeout(()=>pushCloud(),700)}
async function beginCloudSession(session){storeSession(session);document.getElementById('authDialog').close();document.getElementById('lastSaved').textContent='Connecting…';await pullCloud(true);clearInterval(cloudTimer);cloudTimer=setInterval(()=>pullCloud(),15000)}
function openAuth(){let dialog=document.getElementById('authDialog');document.getElementById('authError').textContent='';if(!dialog.open)dialog.showModal()}
function setAuthMode(mode){authMode=mode;let signup=mode==='signup';document.getElementById('authTitle').textContent=signup?'Create leader account':'Sign in to continue';document.getElementById('authIntro').textContent=signup?'Create an account using your department email.':'Use your department leader account to access the shared workspace.';document.getElementById('authSubmit').textContent=signup?'Create account':'Sign in';document.getElementById('authSwitch').textContent=signup?'Already registered? Sign in':'Need an account? Create one';document.getElementById('authPassword').autocomplete=signup?'new-password':'current-password'}
async function initCloud(){let saved=JSON.parse(localStorage.getItem(SESSION_KEY)||'null');if(saved?.access_token){cloudSession=saved;if(saved.expires_at&&saved.expires_at*1000<Date.now()+60000)await refreshCloudSession();if(cloudSession){await beginCloudSession(cloudSession);return}}openAuth()}
document.getElementById('authDialog').addEventListener('cancel',event=>{if(!cloudSession)event.preventDefault()});
document.getElementById('authSwitch').onclick=()=>setAuthMode(authMode==='signin'?'signup':'signin');
document.getElementById('authForm').onsubmit=async event=>{event.preventDefault();let button=document.getElementById('authSubmit'),error=document.getElementById('authError'),email=document.getElementById('authEmail').value.trim(),password=document.getElementById('authPassword').value;button.disabled=true;button.textContent=authMode==='signup'?'Creating account…':'Signing in…';error.textContent='';try{if(authMode==='signup'){let data=await authRequest('signup',{email,password});if(data.access_token)await beginCloudSession(data);else{setAuthMode('signin');error.classList.add('success');error.textContent='Account created. Check your email to confirm it, then sign in.'}}else{let data=await authRequest('token?grant_type=password',{email,password});await beginCloudSession(data)}}catch(err){error.classList.remove('success');error.textContent=err.message}finally{button.disabled=false;button.textContent=authMode==='signup'?'Create account':'Sign in'}};
document.getElementById('accountButton').onclick=()=>{if(!cloudSession){openAuth();return}document.getElementById('accountDialog').showModal();updateNotificationStatus()};
document.getElementById('accountClose').onclick=()=>document.getElementById('accountDialog').close();
document.getElementById('signOutButton').onclick=async()=>{try{await fetch(`${SUPABASE_URL}/auth/v1/logout`,{method:'POST',headers:supabaseHeaders()})}catch{}clearInterval(cloudTimer);cloudSession=null;cloudReady=false;localStorage.removeItem(SESSION_KEY);document.getElementById('accountDialog').close();document.getElementById('accountButton').textContent='IA';document.getElementById('lastSaved').textContent='Saved offline';openAuth()};
function vapidBytes(value){let padding='='.repeat((4-value.length%4)%4),base64=(value+padding).replace(/-/g,'+').replace(/_/g,'/'),raw=atob(base64),bytes=Uint8Array.from([...raw].map(char=>char.charCodeAt(0)));if(bytes.length!==65||bytes[0]!==4)throw new Error('The notification public key is invalid. Ask the administrator to update the app.');return bytes.buffer}
async function currentPushSubscription(){if(!('serviceWorker' in navigator)||!('PushManager' in window))return null;let registration=await navigator.serviceWorker.ready;return registration.pushManager.getSubscription()}
async function updateNotificationStatus(){let status=document.getElementById('notificationStatus'),button=document.getElementById('notificationButton');if(!('Notification' in window)||!('PushManager' in window)){status.textContent='Not supported by this browser';button.disabled=true;return}let subscription=await currentPushSubscription();if(subscription&&Notification.permission==='granted'){status.textContent='Enabled on this device';button.textContent='Disable';button.classList.remove('gold')}else{status.textContent=Notification.permission==='denied'?'Blocked in browser settings':'Not enabled on this device';button.textContent='Enable';button.classList.add('gold')}}
async function enableNotifications(){if(!cloudSession){toast('Sign in first');return}let button=document.getElementById('notificationButton'),isIOS=/iPhone|iPad|iPod/i.test(navigator.userAgent),standalone=window.matchMedia('(display-mode: standalone)').matches||navigator.standalone===true;button.disabled=true;try{if(isIOS&&!standalone)throw new Error('On iPhone, open Illuminate from its Home Screen icon before enabling notifications.');let existing=await currentPushSubscription();if(existing){await cloudFetch(`push_subscriptions?endpoint=eq.${encodeURIComponent(existing.endpoint)}`,{method:'DELETE',headers:{'Prefer':'return=minimal'}});await existing.unsubscribe();toast('Notifications disabled on this device')}else{let permission=await Notification.requestPermission();if(permission!=='granted')throw new Error('Notifications were not allowed. Enable them for Illuminate in iPhone Settings.');let registration=await navigator.serviceWorker.ready,subscription=await registration.pushManager.subscribe({userVisibleOnly:true,applicationServerKey:vapidBytes(VAPID_PUBLIC_KEY)}),payload={user_id:cloudSession.user.id,endpoint:subscription.endpoint,subscription:subscription.toJSON(),device_label:navigator.userAgent.slice(0,160)};await cloudFetch('push_subscriptions?on_conflict=endpoint',{method:'POST',headers:{'Prefer':'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(payload)});toast('Device notifications enabled')}}catch(error){let message=error?.message||'Could not enable notifications';if(isIOS&&/string did not match|expected pattern|not supported|abort|invalid/i.test(message))message='iPhone could not create the notification subscription. Confirm iOS 16.4 or later, then remove the Home Screen app and add it again from Safari after publishing this update.';toast(message)}finally{button.disabled=false;try{await updateNotificationStatus()}catch{}}}
document.getElementById('notificationButton').onclick=enableNotifications;
document.getElementById('notificationBell').onclick=()=>{current='notifications';render()};
document.getElementById('view').addEventListener('click',event=>{let downloadButton=event.target.closest('[data-download-design]');if(downloadButton){downloadDesignFile(downloadButton.dataset.downloadDesign);return}let notification=event.target.closest('[data-notification-key]');if(notification){markNotificationRead(notification.dataset.notificationKey);current=notification.dataset.notificationPage;render();return}if(event.target.closest('#markAllNotifications'))markAllNotificationsRead()});
let installPrompt=null;window.addEventListener('beforeinstallprompt',event=>{event.preventDefault();installPrompt=event});
window.addEventListener('appinstalled',()=>toast('Illuminate DMS installed'));
if('serviceWorker' in navigator)window.addEventListener('load',()=>navigator.serviceWorker.register('./service-worker.js').catch(()=>{}));
let designPreviewUrls=[];
function postRenderEnhancements(){
  if(current==='contributions')decorateContributionRows();
  if(current==='schedule')decorateMeetingTemplate();
  if(current==='designs')loadDesignThumbnails();
}
function decorateContributionRows(){
  document.querySelectorAll('#view [data-edit="contribution"]').forEach(edit=>{
    let cell=edit.closest('tr')?.cells?.[0];
    if(!cell||cell.querySelector('[data-view-contribution]'))return;
    let button=document.createElement('button');
    button.type='button';button.className='contribution-link';button.dataset.viewContribution=edit.dataset.id;
    button.title='View members who contributed';button.innerHTML=cell.innerHTML;cell.replaceChildren(button);
    button.onclick=()=>openContributionDetails(edit.dataset.id);
  });
}
function openContributionDetails(id){
  let contribution=state.contributionTypes.find(item=>item.id===id),dialog=document.getElementById('contributionDialog'),body=document.getElementById('contributionDetailBody');
  if(!contribution||!dialog||!body)return;
  let grouped={};
  state.payments.filter(payment=>payment.typeId===id).forEach(payment=>{let key=payment.memberId||'unknown';if(!grouped[key])grouped[key]={amount:0,dates:[]};grouped[key].amount+=Number(payment.amount||0);if(payment.date)grouped[key].dates.push(payment.date)});
  let contributors=Object.entries(grouped).map(([memberId,value])=>({memberId,...value})).filter(item=>item.amount>0).sort((a,b)=>memberName(a.memberId).localeCompare(memberName(b.memberId)));
  let received=contributors.reduce((sum,item)=>sum+item.amount,0),perMember=Number(contribution.amount||0);
  document.getElementById('contributionDetailTitle').textContent=contribution.name;
  document.getElementById('contributionDetailSummary').textContent=`${contributors.length} member${contributors.length===1?'':'s'} contributed · ${money(received)} received`;
  body.innerHTML=contributors.length?`<div class="table-wrap"><table class="data-table contributor-table"><thead><tr><th>Member</th><th>Amount contributed</th><th>Balance</th><th>Latest payment</th></tr></thead><tbody>${contributors.map(item=>`<tr><td><strong>${esc(memberName(item.memberId))}</strong></td><td>${money(item.amount)}</td><td>${money(Math.max(0,perMember-item.amount))}</td><td>${dateFmt(item.dates.sort().at(-1)||'')}</td></tr>`).join('')}</tbody></table></div>`:empty('No member has contributed yet');
  if(!dialog.open)dialog.showModal();
}
function decorateMeetingTemplate(){
  let template=document.querySelector('#view .editable-template[data-template="schedule"]'),wrap=template?.querySelector('.table-wrap');
  if(!wrap||template.querySelector('[data-add-agenda-row]'))return;
  let button=document.createElement('button');button.type='button';button.className='button ghost add-agenda-row';button.dataset.addAgendaRow='';button.textContent='＋ Add activity line';
  button.onclick=()=>{let body=template.querySelector('tbody'),row=document.createElement('tr'),index=body.rows.length;row.innerHTML=Array.from({length:6},(_,cell)=>`<td contenteditable="true" data-cell="${index},${cell}"></td>`).join('');body.appendChild(row);row.cells[0].focus();};
  wrap.insertAdjacentElement('afterend',button);
}
async function loadDesignThumbnails(){
  designPreviewUrls.forEach(url=>URL.revokeObjectURL(url));designPreviewUrls=[];
  let cards=[...document.querySelectorAll('#view .design-card')];
  await Promise.all(cards.map(async card=>{
    let id=card.querySelector('[data-edit="design"]')?.dataset.id,design=state.designs.find(item=>item.id===id),thumb=card.querySelector('.design-thumb');
    if(!design?.filePath||!thumb)return;
    let imageFile=(design.fileType||'').startsWith('image/')||/\.(png|jpe?g|webp|gif)$/i.test(design.fileName||'');
    if(!imageFile)return;
    try{let response=await fetch(`${SUPABASE_URL}/storage/v1/object/authenticated/design-files/${storagePath(design.filePath)}`,{headers:{apikey:SUPABASE_KEY,Authorization:`Bearer ${cloudSession?.access_token||SUPABASE_KEY}`}});if(!response.ok)throw new Error('Preview unavailable');let blob=await response.blob(),url=URL.createObjectURL(blob);designPreviewUrls.push(url);let image=document.createElement('img');image.src=url;image.alt=`${design.category||'Design'} preview`;image.loading='lazy';thumb.replaceChildren(image);thumb.classList.add('has-image')}catch{thumb.title='Sign in to preview this design'}
  }));
}
let initialPage=location.hash.slice(1);if(pages.some(page=>page[0]===initialPage))current=initialPage;
render();initCloud();
